        $result.NewVersion | Should -Be "3.0.0"
        $result.BumpType | Should -Be "none"
    }

    AfterEach {
        if ($tmpDir -and (Test-Path $tmpDir)) {
            Remove-Item -Recurse -Force $tmpDir
        }
    }
}

